class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        unordered_map<int, int> pos;
        for (int i = 0; i < row.size(); ++i) {
            pos[row[i]] = i;
        }
        int swaps = 0;
        for (int i = 0; i < n; ++i) {
            int partner = row[2 * i] ^ 1;
            if (row[2 * i + 1] != partner) {
                swaps++;
                int partnerPos = pos[partner];
                swap(row[2 * i + 1], row[partnerPos]);
                pos[row[partnerPos]] = partnerPos;
                pos[partner] = 2 * i + 1;
            }
        }
        return swaps;
    }
};
